// Public-facing worker that accepts user requests and forwards them to internal workers for processing
addEventListener("fetch", event => {
  const request = event.request;
  // Forward the request to an internal worker based on the URL path
  const url = new URL(request.url);
  const path = url.pathname;
  if (path === "/api/internal-worker") {
    const internalWorker = new Request("https://example.com/internal-worker", {
      method: "POST",
      body: request.body,
      headers: request.headers,
    });
    event.respondWith(fetch(internalWorker));
  } else {
    // Handle other requests as needed
  }
});